import{_ as e,c as r,o as i,ag as a}from"./chunks/framework.Ds6Eueu6.js";const o="/bit_1.jpg",p="/matri.png",s="/bit.jpg",g=JSON.parse('{"title":"BIT","description":"","frontmatter":{},"headers":[],"relativePath":"broker/bit.md","filePath":"broker/bit.md","lastUpdated":null}'),n={name:"broker/bit.md"};function c(l,t,_,m,d,b){return i(),r("div",null,t[0]||(t[0]=[a('<h1 id="bit" tabindex="-1">BIT <a class="header-anchor" href="#bit" aria-label="Permalink to &quot;BIT&quot;">​</a></h1><p>BIT（原 Matrixport）成立于 2019 年，是一家以诚信为本的全球数字资产金融服务集团。集团总部位于新加坡，在全球七个国家和地区设有办公室，通过稳健的治理体系、技术能力与合规运营，连接传统金融与数字资产市场。</p><p>BIT 为全球机构及专业投资者提供涵盖交易、托管、资产管理、流动性及融资方案，并支持现实世界资产（RWA）的链上引入与应用。旗下实体在新加坡、香港、瑞士、英国、美国及不丹持有相应牌照并受当地监管，其中包括新加坡大型支付机构牌照（MPI）及瑞士 FINMA 颁发的集合资产管理牌照。</p><p>目前集团管理资产规模超过 60 亿美元，月交易量超 70 亿美元，累计向客户支付利息总额超过 20 亿美元，估值超 10 亿美元，曾入选《2024 胡润全球独角兽榜》及《2025 新加坡金融科技独角兽榜》。</p><p><img src="'+o+'" alt=""></p><p>BIT 已获得香港的信托或公司服务提供者（TCSP）牌照和放债人牌照，以及瑞士的 FINMA 资产管理牌照。公司在英国以委任代表身份运营，在美国注册为 MSB，并且是瑞士 FINMA SRO-VFQ 的成员。此外，Matrixport 的子公司 Fly Wing 已获得新加坡金管局颁发的 MPI 牌照。公司还被 CB Insights 评选为50 家最具前景的区块链公司之一，入选胡润2024 全球独角兽榜，并于 2025 年被认定为新加坡金融科技独角兽。</p><p><img src="'+p+'" alt=""></p><div class="info custom-block"><p class="custom-block-title">🔔 立即开户：</p><ul><li><p>专属链接：<a href="https://invest.matrixport.com/newRegister/cn?invite_code=9YZ5GD" target="_blank" rel="noreferrer">https://invest.matrixport.com/newRegister/cn?invite_code=9YZ5GD</a></p></li><li><p>邀请码：【9YZ5GD】</p></li></ul><p><img src="'+s+'" alt=""></p></div>',8)]))}const T=e(n,[["render",c]]);export{g as __pageData,T as default};
